const express = require('express');
const crypto = require('crypto');
const querystring = require('querystring');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// Define our authorization code storage in memory
let authCodes = {};

// This would normally be a database or other persistent data store

app.get('/authorize', (req, res) => {
    // Generate an authorization code and store it for the user's session
    let code = crypto.randomBytes(20).toString('hex');
    authCodes[code] = true;
  
    // Redirect the user to a consent page, with the authorization code in the query string
    res.redirect(req.query.redirect_uri + '?code=' + code);
});

app.post('/token', (req, res) => {
    let code = req.body.code;
  
    // If we have a valid authorization code and haven't already exchanged it for an access token, issue an access token
    if (authCodes[code]) {
        delete authCodes[code];
      
        // This is where you would generate the actual access token, but for this example we'll just send a fake one
        res.json({access_token: 'fake_access_token', token_type: 'Bearer'});
    } else {
        // If the authorization code isn't valid, return an error
        res.status(400).json({error: 'invalid_grant'});
    }
});

app.listen(3000, () => console.log('Server listening on port 3000'));